INSERT INTO "Review" ("id", "userId", "name", "educationalInstitution", "rating", "text", "isPublished", "createdAt") VALUES
('cmp67i07z05pllk9celwjqr8q', 'cmp5n9dkd004ugnmmq0givxm7', 'Бобровский Виталий', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '4', 'Сдал полностью, баллы и сертификат на месте. За четыре звезды: понятная навигация, адекватные тесты, практика близкая к «жизни». Пятый балл не поставил из‑за редких мелких огрехов в формулировках заданий.', 't', '2026-04-12 13:19:49.445'),
('cmp67i08805qllk9cudd7a5gt', 'cmp5n9dl10066gnmmdvxx5d1b', 'Прядезникова Диана', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '5', 'Отлично структурировано: от простого к сложному, везде понятно, зачем этот шаг. Практика с ручной проверкой мотивировала не халтурить. После выдачи сертификата спокойно рассказываю одногруппникам, с чего начать ИБ.', 't', '2026-04-15 15:13:44.125'),
('cmp67i08e05r9lk9cwcc50agi', 'cmp5n9dlm0073gnmmi2y8ysif', 'Шадрин Артем', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '4', 'Сдал полностью, баллы и сертификат на месте. За четыре звезды: понятная навигация, адекватные тесты, практика близкая к «жизни». Пятый балл не поставил из‑за редких мелких огрехов в формулировках заданий.', 't', '2026-04-11 02:28:28.146'),
('cmp67i07y05phlk9c7h8vd3kl', 'cmp5n9dk8004ognmmgxx1oxgb', 'Арылахова Лилия', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '2', 'Сертификат есть, но вовлечение среднее: часть модулей ощущались как «прочитай и ответь». Для галочки подойдёт.', 't', '2026-04-14 14:48:04.63'),
('cmp67i06z05lplk9cyqeynk9s', 'cmp66xj6900jilktg3l2371hj', 'Габышев Владимир Петрович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '3', 'Прошла курс целиком. Нормально для программы: тесты честные, по практике комментарии полезные. Без «вау», но знания по ИБ реально прибавились.', 't', '2026-04-12 17:43:30.671'),
('cmp67i07g05nhlk9ceufvlcqv', 'cmp677s8x00lxlk1vlegzof4i', 'Стифоров Тимур Сергеевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-24, 2 курс', '5', 'Очень понравилось, что нельзя «прокликать» практику бездумно — проверка реально заставляет думать. Курс полностью прошёл, сертификатом доволен.', 't', '2026-04-11 17:59:29.14'),
('cmp67i08i05rnlk9cjlv1shlg', 'cmp5neihq007lgn7xpes1pyr0', 'Васильев Андрей', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '5', 'Очень понравилось, что нельзя «прокликать» практику бездумно — проверка реально заставляет думать. Курс полностью прошёл, сертификатом доволен.', 't', '2026-04-12 23:56:31.718'),
('cmp67i08k05rtlk9ckyf4iqu0', 'cmp5neihy007ugn7x983naezw', 'Горохова Алина', 'ГАПОУ «ЯКСИТ», группа ИСИП-24/1, 2 курс', '2', 'Завершила курс из упрямства — в целом полезно, но ожидала большей гибкости по срокам и более разжёванных объяснений в паре модулей. За идею и сертификат спасибо, за подачу — на четвёрку не потянет.', 't', '2026-04-15 10:58:01.43'),
('cmp67i06o05kflk9cj2ebacre', 'cmp66xiz700hrlktgnos3ruh6', 'Дьяконов Виктор Андреевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '5', 'Отлично структурировано: от простого к сложному, везде понятно, зачем этот шаг. Практика с ручной проверкой мотивировала не халтурить. После выдачи сертификата спокойно рассказываю одногруппникам, с чего начать ИБ.', 't', '2026-04-11 11:26:37.475'),
('cmp67i07805mnlk9cpm7ni2lc', 'cmp5md6210020gnc052rt4i5j', 'Чернов Андрей Васильевич', 'Якутский гуманитарный колледж, группа КИ-24, 3 курс', '2', 'Сертификат есть, но вовлечение среднее: часть модулей ощущались как «прочитай и ответь». Для галочки подойдёт.', 't', '2026-04-12 03:12:21.191'),
('cmp67i07b05mxlk9ce94or3tp', 'cmp677s8600l6lk1vblisnru2', 'Григорьев Олег Трофимович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-24, 2 курс', '5', 'Отлично структурировано: от простого к сложному, везде понятно, зачем этот шаг. Практика с ручной проверкой мотивировала не халтурить. После выдачи сертификата спокойно рассказываю одногруппникам, с чего начать ИБ.', 't', '2026-04-16 23:15:13.277'),
('cmp67i07p05oflk9cssihipl3', 'cmp5mtbpj0039gnh8viinzir4', 'Николаев Григорий', 'ГАПОУ «ЯКСИТ», группа ОИБ-25, 1 курс', '5', 'Сильная линейка модулей, всё связано с реальными ошибками пользователей. Прошёл до конца без «затыков». Сертификат — приятное подтверждение, что не зря вложился.', 't', '2026-04-16 12:04:52.353'),
('cmp67i07z05pjlk9c7pi7wt4x', 'cmp5n9dkb004rgnmm06jw7voy', 'Ашихмин Павел', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '4', 'Хороший баланс теории и проверок. Все модули закрыл, к сертификату претензий нет. Звезду снял за то, что мобильная вёрстка местами прыгает.', 't', '2026-04-11 04:48:23.109'),
('cmp67i06s05kvlk9cq1jkle76', 'cmp66xizh00iclktgkxmionlb', 'Прокопьев Максим Васильевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '4', 'Сдал полностью, баллы и сертификат на месте. За четыре звезды: понятная навигация, адекватные тесты, практика близкая к «жизни». Пятый балл не поставил из‑за редких мелких огрехов в формулировках заданий.', 't', '2026-04-12 05:28:05.5'),
('cmp67i08805qnlk9c535zvtw6', 'cmp5n9dl20069gnmmru3b3w1e', 'Семенов Роман', 'ГАПОУ «ЯКСИТ», группа ИСИП-25, 1 курс', '3', 'Прошла полностью, сертификат получила. В целом нормально: базу по ИБ собрала, тесты адекватные. Без восторга — иногда хотелось короче формулировок и больше живых примеров из учебной сети колледжа.', 't', '2026-04-16 10:37:17.497');